INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('aerospace_aerospace_engineer', 'Aerospace', 'Aerospace Engineer', 'I am writing to express my strong interest in the {role_type} position at {company_name}. As a {years}-year military veteran with extensive experience in {domain}, I bring a unique combination of leadership, discipline, and technical expertise that directly aligns with your team''s needs.', 'With {years} years in military aviation/space operations, I bring deep expertise in mission planning, flight operations, and aerospace systems management. I have managed assets valued at ${value}+, maintained {safety_record} safety records, and led teams of {team_size} in executing complex operations. My experience directly supports {company_name}''s aerospace mission.', 'Beyond technical qualifications, my military experience has developed exceptional soft skills that are critical in any organization. I am adept at building high-performing teams, communicating complex information to diverse audiences, and maintaining composure under pressure. I bring a strong work ethic, unwavering integrity, and a commitment to continuous improvement that will add immediate value to your organization.', 'I would welcome the opportunity to discuss how my military experience and skills can contribute to {company_name}''s success. I am available for an interview at your convenience and can be reached at {phone} or {email}. Thank you for considering my application, and I look forward to the possibility of joining your team.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Aerospace Aerospace Engineer roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('aerospace_mission_planner', 'Aerospace', 'Mission Planner', 'With {years} years of proven leadership and operational excellence in the {branch}, I am excited to apply for the {role_type} role at {company_name}. My military career has equipped me with the skills, resilience, and results-driven mindset that {company_name} values.', 'My career in military aerospace operations has prepared me for civilian roles requiring precision, reliability, and technical excellence. I have experience in satellite operations, mission control, and systems engineering. I am excited to contribute to {company_name}''s innovative aerospace programs.', 'What sets me apart is not just my technical background but the leadership philosophy I developed through military service. I believe in servant leadership, accountability, and empowering team members to achieve their full potential. I have consistently built teams that exceed expectations, and I am eager to bring this approach to {company_name}.', 'Thank you for considering my application for the {role_type} position. I am confident that my {years} years of military leadership and operational experience make me a strong candidate. I welcome the opportunity to discuss how I can contribute to {company_name}''s mission and would be happy to provide additional references or information upon request.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Aerospace Mission Planner roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('aerospace_flight_ops_manager', 'Aerospace', 'Flight Ops Manager', 'I am eager to bring my {years} years of military experience to the {role_type} position at {company_name}. My background in {domain} has prepared me to deliver immediate value in a fast-paced civilian environment.', 'With {years} years in military aviation/space operations, I bring deep expertise in mission planning, flight operations, and aerospace systems management. I have managed assets valued at ${value}+, maintained {safety_record} safety records, and led teams of {team_size} in executing complex operations. My experience directly supports {company_name}''s aerospace mission.', 'My military training has instilled in me a deep appreciation for teamwork, planning, and execution. I am accustomed to working in environments where precision matters, deadlines are non-negotiable, and adaptability is essential. These qualities, combined with my commitment to professional development and continuous learning, make me a strong addition to your team.', 'I am enthusiastic about the opportunity to bring my military-honed skills to {company_name} and am confident I can make an immediate impact. I would appreciate the chance to discuss my qualifications in more detail. Please feel free to contact me at {phone} or {email} to schedule a conversation.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Aerospace Flight Ops Manager roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('aerospace_quality_engineer', 'Aerospace', 'Quality Engineer', 'As a transitioning military professional with {years}+ years of service, I am confident that my expertise in {domain} makes me an excellent candidate for the {role_type} position at {company_name}. I have consistently delivered results in high-stakes environments and am ready to bring that same commitment to your organization.', 'My career in military aerospace operations has prepared me for civilian roles requiring precision, reliability, and technical excellence. I have experience in satellite operations, mission control, and systems engineering. I am excited to contribute to {company_name}''s innovative aerospace programs.', 'I am particularly drawn to {company_name} because of your commitment to {company_value}. My military background has given me firsthand experience with the importance of {related_value}, and I am excited to contribute to an organization that shares these principles. I am confident that my leadership experience and technical skills will help drive your team''s success.', 'I look forward to the opportunity to discuss how my background in {domain} aligns with {company_name}''s goals. My military service has prepared me to excel in demanding environments, and I am eager to demonstrate my value to your organization. Thank you for your time and consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Aerospace Quality Engineer roles') ON CONFLICT DO NOTHING;
